import{c as i,S as a,j as t,m as n}from"./chunks/framework.BXgR76oC.js";const m=JSON.parse('{"title":"For Maintainers","description":"","frontmatter":{},"headers":[],"relativePath":"guide/maintainers.md","filePath":"guide/maintainers.md","lastUpdated":1779780644000}'),l={name:"guide/maintainers.md"};function o(r,e,s,c,d,p){return a(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="for-maintainers" tabindex="-1">For Maintainers <a class="header-anchor" href="#for-maintainers" aria-label="Permalink to “For Maintainers”">​</a></h1><p>Gittensory is meant to make Gittensor-driven contribution flow less noisy.</p><h2 id="github-app-surface" tabindex="-1">GitHub App Surface <a class="header-anchor" href="#github-app-surface" aria-label="Permalink to “GitHub App Surface”">​</a></h2><p>The GitHub App creates the detailed maintainer surface:</p><ul><li>Gittensory check runs on PRs</li><li>reviewability context</li><li>linked issue and duplicate signals</li><li>contributor role context</li><li>queue and repo-lane context</li><li>optional public-safe sticky PR comments</li></ul><p>The check run is the canonical detailed report. Public comments are opt-in and sanitized.</p><h2 id="reviewability-actions" tabindex="-1">Reviewability Actions <a class="header-anchor" href="#reviewability-actions" aria-label="Permalink to “Reviewability Actions”">​</a></h2><p>Gittensory maps PRs to maintainer-friendly actions:</p><ul><li><code>review_now</code></li><li><code>needs_author</code></li><li><code>likely_duplicate</code></li><li><code>close_or_redirect</code></li><li><code>watch</code></li><li><code>maintainer_lane</code></li></ul><p>The point is not to shame contributors. The point is to identify the lowest-friction next step.</p><h2 id="public-comments" tabindex="-1">Public Comments <a class="header-anchor" href="#public-comments" aria-label="Permalink to “Public Comments”">​</a></h2><p>Public comments stay off by default.</p><p>When enabled, comments can include:</p><ul><li>contribution context</li><li>PR hygiene</li><li>duplicate or WIP risk</li><li>maintainer review notes</li><li>contributor next steps</li></ul><p>Comments must not include raw trust scores, wallet data, hotkeys, public reward estimates, or public score optimization language.</p><h2 id="repo-owner-signals" tabindex="-1">Repo Owner Signals <a class="header-anchor" href="#repo-owner-signals" aria-label="Permalink to “Repo Owner Signals”">​</a></h2><p>Repo owners can use Gittensory to inspect:</p><ul><li>repo lane clarity</li><li>label configuration</li><li>maintainer cut readiness</li><li>queue health</li><li>contributor intake health</li><li>GitHub App installation health</li><li>stale or degraded backfill state</li></ul>',18)])])}const h=i(l,[["render",o]]);export{m as __pageData,h as default};
